VALUES
  ('heelevel3-5ff21eeb-moex-00104', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '依113年修正房屋稅條例規定，下列有關房屋稅住家用房屋之敘述，何者正確？①一般自住用房', '["房屋無出租使用", "供房屋所有人本 人、配偶或直系親屬實際居住使用且應於該屋辦竣戶籍登記", "本人、配偶及直系親屬全國合計 3戶以內  ⑤供公益出租人出租使用者，不適用住家用房屋稅優惠稅率", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00105', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，下列何者應視為銷售貨物或勞務？①以產製之貨物轉供營業', '["營業人解散或廢止時所餘存之貨物分配給股東", "因信託行為成立，委託人將貨物移 轉給受託人", "營業人銷售代銷貨物者  ⑤執行業務者提供專業性勞務以取得代價", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00106', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '有關營業稅之課徵，下列敘述何者正確？①會計師事務所提供審計服務收取之公費收入應適用', '["免稅商店銷售與過境或出境旅客之貨物應適用零稅率", "本國籍航空公司搭載客、 貨自臺灣離島飛至臺灣本島，航程全部票價免稅", "醫院出租財產取得租金收入，免徵營業稅 ⑤國內某大學向國外某機構購買供學術使用之數位資料庫，供教師或學生上網查詢使用，需報繳 購買國外勞務營業稅", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00107', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，下列有關營業稅課徵的敘述，何者正確？', '["夜總會按特種稅額計算，其稅率為25%", "銀行業按特種稅額計算，其經營銀行本業稅率為2%", "銷售農產品之小規模營業人按特種稅額計算，其稅率為0.1%", "百貨業按特種稅額計算，其稅率為5%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00108', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '甲早餐店係由稽徵機關按查定計算稅額之小規模營業人，其每月查定銷售額為新臺幣160,000元， 已取得並依限申報符合規定之進項憑證稅額為 8,000 元，則依加值型及非加值型營業稅法規定， 其當期應納營業稅額為多少？', '["4,800元", "4,000元", "1,600元", "800元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00109', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '下列有關地價稅的相關稅法規定，下列何者正確？', '["因信託行為成立，委託人將土地移轉給受託人，應與受託人在同一直轄市或縣（市）轄區內所 有之土地合併計算地價總額", "供公共通行之騎樓走廊地，地上有建築改良物四層者，減徵四分之一", "無償供給政府機關使用之土地，在使用其期間內，免徵地價稅", "甲於112年8月30日完成登記將其持有土地移轉予乙，則112年地價稅應以甲為納稅義務人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00110', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '有關房屋稅、所得稅的相關規定，下列敘述何者正確？', '["房屋為信託財產者，於自益信託關係存續中，以受託人為房屋稅納稅義務人", "公益出租人出租房屋，其租金收入免納所得稅，房屋稅稅率為1.2%", "受重大災害，房屋毀損面積占整棟五成以上，必須修復始能使用者，房屋稅減半徵收", "住宅房屋轉作社會住宅包租代管，每屋每月租金收入1.5萬元免納所得稅，且房屋稅減半徵收"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00111', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '依113年修正房屋稅條例規定，下列那些使用情況應課徵房屋稅？①政府持有之公有房屋配供一', '["信眾無償提供寺廟作為祭祀使用之房屋", "私立學校之學生宿舍", "慈善團體 附設免費圖書館之房屋  ⑤住家用房屋現值在新臺幣10萬元以下，其超過3戶部分", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00112', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '有關地價稅之課徵，下列敘述何者正確？', '["王先生於111年7月1日購買自用住宅，並且完成產權登記，同年9月30日向稅捐稽徵處申 辦自用住宅優惠稅率，則該戶自用住宅優惠稅率自111年9月30開始適用", "我國地價稅之課徵期間為每年7月1日至次年6月30日", "坐落於臺中市的土地，地價稅由臺中市政府地方稅務局根據地價歸戶冊及地籍異動通知資料核 定徵收", "土地所有權人與其配偶及受扶養親屬適用自用住宅用地稅率繳納地價稅者，以一處為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00113', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '納稅義務人不能於法定期間內繳清稅捐者，依稅捐稽徵法之規定，下列敘述何者正確？', '["納稅義務人依法應繳納所得稅，因客觀事實發生財務困難，得於規定納稅期限內，向稅捐稽徵 機關申請分期或延期繳納", "經稅捐稽徵機關查獲應補徵鉅額稅捐，納稅義務人得於規定納稅期限內，向稅捐稽徵機關申請 分期繳納", "納稅義務人遭遇景氣低迷、經營虧損，得於規定納稅期間內，向稅捐稽徵機關申請分期或延期 繳納", "因天災、事變、不可抗力之事由，經核准延期或分期繳納稅捐者需另加計利息，且期間不得逾3年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
